"""
T2 RBAC System -- Document Routes (Sample 2)

Variant strategy differences from Sample 1:
- Set-based permission checks using issuperset() and frozenset for compile-time safety
- Explicit field extraction pattern for PUT with type validation per field
- Centralised tenant filter helper to reduce query duplication
- Ownership guard as a standalone predicate function (can_edit_document)
- Request body parsed via _extract_json() wrapper for consistent error responses
- Uses db.session.get() (SQLAlchemy 2.x style) for primary-key lookups where available
"""

from flask import Blueprint, request, jsonify, g
from models import Document
from middleware import check_permission
from app import db

document_bp = Blueprint('document_bp', __name__)

# Permission constants as frozensets for set-based checks
_PERM_READ = frozenset({'doc.read'})
_PERM_WRITE = frozenset({'doc.write'})
_PERM_WRITE_ANY = frozenset({'doc.write.any'})
_PERM_DELETE = frozenset({'doc.delete'})


def _extract_json():
    """Parse request JSON body. Returns (dict, error_response) tuple.
    Centralises body parsing so every endpoint gets consistent 400 errors.
    """
    body = request.get_json(silent=True)
    if not isinstance(body, dict):
        return None, (jsonify({'status': 'error', 'message': 'Request body must be JSON'}), 400)
    return body, None


def _serialise(doc):
    """Convert a Document ORM row to a plain dict."""
    return {
        'id': doc.id,
        'tenant_id': doc.tenant_id,
        'owner_id': doc.owner_id,
        'title': doc.title,
        'content': doc.content,
    }


def _tenant_docs_query(tenant_id):
    """Return a base query filtered to the given tenant."""
    return Document.query.filter_by(tenant_id=tenant_id)


def _can_edit_document(user_perms, document):
    """Ownership guard predicate: returns True if the user can edit this document.
    Requires doc.write AND either ownership or doc.write.any permission.
    """
    if not _PERM_WRITE.issubset(user_perms):
        return False
    if _PERM_WRITE_ANY.issubset(user_perms):
        return True
    return document.owner_id == g.current_user.id


# ---- GET /documents: List all documents for current tenant ----

@document_bp.route('/documents', methods=['GET'])
@check_permission('doc.read')
def list_documents():
    user = g.current_user
    docs = _tenant_docs_query(user.tenant_id).all()
    return jsonify({'status': 'ok', 'data': [_serialise(d) for d in docs]}), 200


# ---- GET /documents/<id>: Retrieve a single document ----

@document_bp.route('/documents/<int:doc_id>', methods=['GET'])
@check_permission('doc.read')
def get_document(doc_id):
    user = g.current_user
    doc = _tenant_docs_query(user.tenant_id).filter_by(id=doc_id).first()
    if doc is None:
        return jsonify({'status': 'error', 'message': 'Document not found'}), 404
    return jsonify({'status': 'ok', 'data': _serialise(doc)}), 200


# ---- POST /documents: Create a new document ----

@document_bp.route('/documents', methods=['POST'])
@check_permission('doc.write')
def create_document():
    body, err = _extract_json()
    if err:
        return err

    user = g.current_user

    title = body.get('title')
    if not isinstance(title, str) or not title:
        return jsonify({'status': 'error', 'message': 'title is required'}), 400

    content = body.get('content', '')
    if not isinstance(content, str):
        content = str(content)

    doc = Document(
        tenant_id=user.tenant_id,
        owner_id=user.id,
        title=title,
        content=content,
    )
    db.session.add(doc)
    db.session.commit()

    return jsonify({'status': 'ok', 'data': _serialise(doc)}), 201


# ---- PUT /documents/<id>: Update an existing document ----

@document_bp.route('/documents/<int:doc_id>', methods=['PUT'])
@check_permission('doc.write')
def update_document(doc_id):
    user = g.current_user
    doc = _tenant_docs_query(user.tenant_id).filter_by(id=doc_id).first()
    if doc is None:
        return jsonify({'status': 'error', 'message': 'Document not found'}), 404

    # Ownership / write-any check
    if not _can_edit_document(g.current_permissions, doc):
        return jsonify({'status': 'error', 'message': 'Permission denied'}), 403

    body, err = _extract_json()
    if err:
        return err

    # Explicit field extraction with type validation
    if 'title' in body:
        new_title = body['title']
        if not isinstance(new_title, str) or not new_title:
            return jsonify({'status': 'error', 'message': 'title must be a non-empty string'}), 400
        doc.title = new_title

    if 'content' in body:
        new_content = body['content']
        if not isinstance(new_content, str):
            new_content = str(new_content)
        doc.content = new_content

    db.session.commit()
    return jsonify({'status': 'ok', 'data': _serialise(doc)}), 200


# ---- DELETE /documents/<id>: Delete a document ----

@document_bp.route('/documents/<int:doc_id>', methods=['DELETE'])
@check_permission('doc.delete')
def delete_document(doc_id):
    user = g.current_user
    doc = _tenant_docs_query(user.tenant_id).filter_by(id=doc_id).first()
    if doc is None:
        return jsonify({'status': 'error', 'message': 'Document not found'}), 404

    db.session.delete(doc)
    db.session.commit()
    return jsonify({'status': 'ok', 'data': None}), 200

